const AVAILABLE_MS = Object.keys(POCKET_MASTER_DELAY_TABLE).map(Number).sort((a, b) => a - b)

export function findClosestDelayMs(targetMs: number): number {
  let closest = AVAILABLE_MS[0]
  let minDiff = Math.abs(targetMs - closest)
  for (const ms of AVAILABLE_MS) {
    const diff = Math.abs(targetMs - ms)
    if (diff < minDiff) { minDiff = diff; closest = ms }
    if (ms > targetMs) break
  }
  return closest
}
